mapper.update:
/* 회원수정 */
UPDATE members


		  mbr_pw = #{memberPw}


		, mbr_name = #{memberName}


		, mbr_grd = #{memberGrade}


		, mbr_addr = #{memberAddress}


		, mbr_daddr = #{memberDetailAddress}


		, mbr_zip = #{memberZip}


		, mbr_telno = #{memberTelNo}


		, mbr_email = #{memberEmail}


WHERE 
	mbr_id = #{memberId};

